import { Button, DialogOverlay, DialogOverlayActions, DialogOverlayFooter } from '@fs/zion-ui'
import React from 'react'
import { Trans, useTranslation } from 'react-i18next'
import useChatBlockUser from '../../hooks/useChatBlockUser'

export default function ChatBlockUserOverlay({ targetUser, overlay }) {
  const [t] = useTranslation()
  const { id: targetUserId, name: targetUserName } = targetUser || {}
  const { blockUser } = useChatBlockUser({ targetUserId, targetUserName })

  const handleBlockClick = () => {
    blockUser()
    overlay.close()
  }

  return (
    <DialogOverlay title={t('chat.block-user.label', 'Block User')} {...overlay}>
      {t(
        'chat.block-user.message',
        '{name} will be blocked and will no longer be able to message you. Previous messages will no longer be visible. To unblock this contact:',
        { name: targetUserName }
      )}
      <ol>
        <Trans
          i18nKey="chat.unblock-user-steps.message"
          defaults="<0>Open the Chat menu ⋮</0><0>Select View Blocked Users</0><0>Click the contact menu and unblock.</0>"
          components={[<li />]}
        />
      </ol>
      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button onClick={overlay.close}>{t('common-ui:cancel.action', 'Cancel')}</Button>
          <Button onClick={handleBlockClick} emphasis="high">
            {t('chat.block.action', 'Block')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
